exact_non_matches_no_manual <-
  exact_non_matches |>
  anti_join(
    fuzzy_matches_embeddings |>
      select(name = name, state),
    by = c("name", "state")
  ) |>
  anti_join(
    fuzzy_matches_manual |>
      select(name = name.a, state),
    by = c("name", "state")
  )

matches <-
  bind_rows(
    exact_matches,
    fuzzy_matches_embeddings |>
      select(name, state, detention_facility_code, source),
    fuzzy_matches_manual |>
      select(name = name.a, state, detention_facility_code),
    hold_rooms_final
    # missing_from_vera
  ) |>
  distinct(detention_facility_code, name, state)

facility_attributes_matched <-
  facility_attributes |>
  select(-detention_facility_code) |>
  inner_join(
    matches,
    by = c("name", "state")
  )

code_name_state_match <-
  bind_rows(
    facility_code,
    facility_attributes_matched
  ) |>
  distinct(detention_facility_code, name, state)

arrow::write_feather(
  code_name_state_match,
  "data/facilities-name-code-match.feather"
)
